+        /// Build a complete JSONL file string from header + entries.
+        fn build_jsonl(header: &str, entry_lines: &[String]) -> String {
+            let mut lines = vec![header.to_string()];
+            lines.extend(entry_lines.iter().cloned());
+            lines.join("\n")
+        }
