+        // ------------------------------------------------------------------
+        // Proptest 3: Valid entries round-trip through serialization
+        // ------------------------------------------------------------------
+        proptest! {
+            #![proptest_config(ProptestConfig {
+                cases: 256,
+                max_shrink_iters: 200,
