+                for i in 0..n_entries {
+                    let eid = format!("{i:08x}");
+                    let parent = if i == orphan_idx {
+                        // Point to a nonexistent parent
+                        Some("deadbeef".to_string())
+                    } else {
+                        prev_id.clone()
+                    };
+
+                    let entry = json!({
+                        "type": "message",
+                        "id": eid,
+                        "parentId": parent,
+                        "timestamp": "2024-01-01T00:00:00.000Z",
+                        "message": {
+                            "role": "user",
